#include <bits/stdc++.h>
using namespace std;

const int N=50010;

int n,a,b,d,miu[N],s[N];
bool p[N];

void init(){
    n=5e4;
    for(int i=1;i<=n;i++)
        miu[i]=1;
    for(int i=2;i<=n;i++)
        if(!p[i]){
            miu[i]=-1;
            for(int j=2;i*j<=n;j++){
                p[i*j]=1;
                if(j%i==0)
                    miu[i*j]=0;
                else
                    miu[i*j]=-miu[i*j];
            }
        }
    for(int i=1;i<=n;i++)
        s[i]=s[i-1]+miu[i];
}

int main(){
    init();
    scanf("%d",&n);
    while(n--){
        scanf("%d%d%d",&a,&b,&d);
        a/=d,b/=d;
        long long ans=0;
        for(int i=1;i<=min(a,b);i=min(a/(a/i),b/(b/i))+1){
            int j=min(a/(a/i),b/(b/i));
            ans+=1LL*(s[j]-s[i-1])*(a/i)*(b/i);
        }
        printf("%lld\n",ans);
    }
    return 0;
}
